styles:
.page-header {
      background: white;
      padding: 8rem 0 4rem;
      text-align: center;
      border-bottom: 1px solid var(--border);
    }
    .page-header h1 {
      font-size: clamp(2rem, 5vw, 3rem);
      margin-bottom: 1rem;
      color: var(--text-primary);
    }
    .page-header p {
      color: var(--text-secondary);
      font-size: 1.125rem;
    }
    .page-content {
      background: white;
      padding: 4rem 0;
    }
    .page-content .container {
      max-width: 800px;
    }
    .intro-section {
      margin-bottom: 3rem;
    }
    .intro-section p {
      color: var(--text-secondary);
      line-height: 1.8;
      margin-bottom: 1rem;
    }
    .job-card {
      background: var(--bg-secondary);
      border: 1px solid var(--border);
      border-radius: var(--radius-lg);
      padding: 2rem;
      margin-bottom: 1.5rem;
      transition: transform 0.2s, box-shadow 0.2s;
    }
    .job-card:hover {
      transform: translateY(-2px);
      box-shadow: 0 8px 24px rgba(0, 0, 0, 0.08);
    }
    .job-card h3 {
      font-size: 1.25rem;
      margin-bottom: 0.5rem;
      color: var(--text-primary);
    }
    .job-meta {
      display: flex;
      flex-wrap: wrap;
      gap: 1rem;
      margin-bottom: 1rem;
      color: var(--text-secondary);
      font-size: 0.875rem;
    }
    .job-meta span {
      display: flex;
      align-items: center;
      gap: 0.25rem;
    }
    .job-type {
      background: var(--primary);
      color: white;
      padding: 0.25rem 0.75rem;
      border-radius: var(--radius-full);
      font-size: 0.75rem;
      font-weight: 600;
    }
    .job-description {
      color: var(--text-secondary);
      line-height: 1.6;
      margin-bottom: 1rem;
    }
    .job-requirements h4 {
      font-size: 0.875rem;
      font-weight: 600;
      color: var(--text-primary);
      margin-bottom: 0.5rem;
    }
    .job-requirements ul {
      color: var(--text-secondary);
      line-height: 1.6;
      padding-left: 1.25rem;
      list-style: disc;
    }
    .job-requirements li {
      margin-bottom: 0.25rem;
    }
    .apply-btn {
      display: inline-flex;
      align-items: center;
      gap: 0.5rem;
      margin-top: 1rem;
      padding: 0.75rem 1.5rem;
      background: var(--primary);
      color: white;
      border-radius: var(--radius);
      font-weight: 500;
      transition: background 0.2s;
    }
    .apply-btn:hover {
      background: var(--primary-dark);
      text-decoration: none;
    }
    .benefits-section {
      margin-top: 4rem;
    }
    .benefits-section h2 {
      font-size: 1.5rem;
      margin-bottom: 1.5rem;
      color: var(--text-primary);
    }
    .benefits-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
      gap: 1.5rem;
    }
    .benefit-item {
      background: var(--bg-secondary);
      padding: 1.5rem;
      border-radius: var(--radius-lg);
    }
    .benefit-item h4 {
      font-size: 1rem;
      margin-bottom: 0.5rem;
      color: var(--text-primary);
    }
    .benefit-item p {
      color: var(--text-secondary);
      font-size: 0.875rem;
      line-height: 1.6;
    }
    .contact-info {
      background: var(--bg-secondary);
      padding: 2rem;
      border-radius: var(--radius-lg);
      margin-top: 3rem;
    }
    .contact-info h3 {
      font-size: 1.25rem;
      margin-bottom: 1rem;
      color: var(--text-primary);
    }
    .contact-info p {
      margin-bottom: 0.5rem;
      color: var(--text-secondary);
    }
    .contact-info a {
      color: var(--primary);
    }
    .contact-info a:hover {
      text-decoration: underline;
    }
    @media (max-width: 768px) {
      .page-header {
        padding: 6rem 0 3rem;
      }
      .page-content {
        padding: 3rem 0;
      }
    }
